#include<iostream>
#include<cstdio>
#include<cstring>
using namespace std;
int n,m,x,y,cnt,fir[300010],dis[300010],w[300010][25],f[300010][25],d[300010],vis[300010],maxx,a[300010],b[300010],cha[300010],ans=1e9,edge[600010],maxbi;
struct ren{
	int e,nex,w;
}bian[600010];
void addedge(int ss,int ee,int ww){
	cnt++;
	bian[cnt].e=ee;
	bian[cnt].w=ww;
	bian[cnt].nex=fir[ss];
	fir[ss]=cnt;
}
void dfs1(int u){
	for(int x=fir[u];x;x=bian[x].nex){
		int en=bian[x].e;
		if(vis[en]==0){
			vis[en]=1;
			d[en]=d[u]+1;		
			f[en][0]=u;
			w[en][0]=bian[x].w;
			dfs1(en);
		}
	}
}
int lujing(int a,int b){
	int ans=0;
	if(d[a]<d[b])swap(a,b);
	for(int i=20;i>=0;i--)
	if(d[f[a][i]]>=d[b]){
		ans+=w[a][i];
		a=f[a][i];
	}
	if(a==b)return ans;
	for(int i=20;i>=0;i--)
	if(f[a][i]!=f[b][i]){
		ans+=w[a][i]+w[b][i];
		a=f[a][i];
		b=f[b][i];
	}
	ans+=w[a][0]+w[b][0];
	return ans;
}
int lca(int a,int b){
	if(d[a]<d[b])swap(a,b);
	for(int i=20;i>=0;i--)
	if(d[f[a][i]]>=d[b])a=f[a][i];
	if(a==b)return a;
	for(int i=20;i>=0;i--)
	if(f[a][i]!=f[b][i]){
		a=f[a][i];
		b=f[b][i];
	}
	return f[a][0];
}
void dfs2(int u){
	for(int x=fir[u];x;x=bian[x].nex){
		int en=bian[x].e;
		if(vis[en]==0){
		vis[en]=1;
		dfs2(en);
		cha[u]+=cha[en]; 
		edge[x]=cha[en];
	}
}
}
int main(){
	cin>>n>>m;
	for(int i=1;i<n;i++){
		int w;		
		scanf("%d%d%d",&x,&y,&w);
		addedge(x,y,w);
		addedge(y,x,w);
	}
	f[1][0]=1;d[1]=1;vis[1]=1;
	dfs1(1);
	for(int i=1;i<=20;i++)
	    for(int u=1;u<=n;u++){
	    	f[u][i]=f[f[u][i-1]][i-1];
	    	w[u][i]=w[f[u][i-1]][i-1]+w[u][i-1];
		}
	for(int i=1;i<=m;i++){
		scanf("%d%d",&a[i],&b[i]);
		dis[i]=lujing(a[i],b[i]);
		maxx=max(maxx,dis[i]);
	}
	for(int i=1;i<=2*(n-1);i++)
	maxbi=max(maxbi,bian[i].w);
	int l=maxx-maxbi,r=300000000,mid;
	while(l<=r){
		mid=(l+r)/2;
		int t=0,maxbian=0;
		memset(edge,0,sizeof(edge));
		memset(cha,0,sizeof(cha));
		memset(vis,0,sizeof(vis));
		for(int i=1;i<=m;i++)
		if(dis[i]>mid){
			cha[a[i]]++;
			cha[b[i]]++;
			cha[lca(a[i],b[i])]-=2;
			t++;
		}
		if(t==0){
			ans=min(ans,mid);
			r=mid-1;
			continue;
		}
		vis[1]=1;
		dfs2(1);	
		for(int i=1;i<=2*(n-1);i++)
		if(edge[i]==t)maxbian=max(maxbian,bian[i].w);
		if(maxx-maxbian<=mid){
			ans=min(ans,mid);
			r=mid-1;
		}
		else l=mid+1;
	}
	cout<<ans;
	return 0;
}
